render.css:
.chart-wrapper { display: flex; flex-direction: column; gap: 10px; height: 100%; }
.kpi-value { font-size: 28px; font-weight: 700; color: var(--ct-text-strong); letter-spacing: -0.02em; }
.chart-container { flex: 1; display: flex; align-items: flex-end; gap: 8px; min-height: 100px; }
.bar { flex: 1; border-radius: 3px 3px 0 0; transition: height var(--ct-dur-base) var(--ct-ease); }
.bar.dark { background: var(--ct-surface-3); }
.bar.light { background: var(--ct-text-strong); }
